prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?message ?messageId ?messageName WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" .
  OPTIONAL { ?model bbo:name ?modelName . }

  ?definitions tai:belongsTo ?model .
  ?message a bboExt:Message ;
           tai:belongsTo ?definitions .
  OPTIONAL { ?message bbo:id ?messageId . }
  OPTIONAL { ?message bbo:name ?messageName . }
  BIND(?message AS ?message)
}
ORDER BY COALESCE(?messageName, STR(?message))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?message ?messageId ?messageName WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "4fba0078103d44d9846d4fbec51710cb" .

  ?definitions tai:belongsTo ?model .
  ?message a bboExt:Message ;
           tai:belongsTo ?definitions .

  OPTIONAL { ?message bbo:id ?messageId . }
  OPTIONAL { ?message bbo:name ?messageName . }
}
ORDER BY COALESCE(?messageName, STR(?message))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?refType ?refValue ?msgElem ?msgName ?msgId WHERE {
  VALUES ?givenId { "4fba0078103d44d9846d4fbec51710cb" }

  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  {
    ?model tai:normalizedId ?givenId .
    BIND("normalizedId" AS ?refType)
    BIND(?givenId AS ?refValue)
  }
  UNION
  {
    ?model tai:originalId ?givenId .
    BIND("originalId" AS ?refType)
    BIND(?givenId AS ?refValue)
  }

  ?definitions tai:belongsTo ?model .

  # Messages referenced by message flows
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?definitions ;
      bboExt:messageRef ?refString .

  # Try to resolve referenced message element by ID suffix
  OPTIONAL {
    ?msgElem a bboExt:Message .
    FILTER(CONTAINS(STR(?msgElem), ?refString))
  }

  OPTIONAL { ?msgElem bbo:name ?msgName . }
  OPTIONAL { ?msgElem bbo:id ?msgId . }
}
ORDER BY COALESCE(?msgName, ?refString, ?msgId)
LIMIT 25
